552→    /// Integration test: auto-mocks are compatible with the Instrument command format.
553→    /// Verifies that generated MockConfig values serialize correctly for the protocol.
554→    #[test]
555→    fn auto_mock_configs_serialize_for_protocol() {
556→        let deps = vec![
557→            make_dep("existsSync", "fs", TypeInfo::Bool),
558→            make_dep("query", "pg", TypeInfo::Unknown),
559→        ];
560→
561→        let mocks = generate_auto_mocks(&deps, None, &HashMap::new(), &[]);
562→        assert_eq!(mocks.len(), 2);
563→
564→        // Verify each mock serializes to valid JSON (required for protocol)
565→        for mock in &mocks {
566→            let json = serde_json::to_value(mock).expect("mock should serialize");
567→            assert!(json.get("symbol").is_some());
568→            assert!(json.get("return_values").is_some());
569→            assert!(json.get("should_track_calls").is_some());
570→            assert!(json.get("default_behavior").is_some());
571→        }
572→    }
