    fn generate_auto_mocks_respects_scope_passthrough() {
        let deps = vec![make_dep("map", "lodash", TypeInfo::Unknown)];
        let scope_config = crate::scope::ScopeConfig {
            include: vec![],
            exclude: vec![],
            mock: vec![],
