            make_dep("get", "axios", TypeInfo::Unknown),
            make_dep("query", "pg", TypeInfo::Unknown),
            make_dep("map", "lodash", TypeInfo::Unknown),
            make_dep("compute", "my-lib", TypeInfo::Int),
